64	smoke-coach-1775418620	active	2026-04-05 19:50:20.812873+00	2026-04-05 19:50:21.02+00	2026-04-05 19:50:21.02+00	1	\N	2026-04-05 19:50:20.882+00	2026-04-05 19:50:21.02+00	\N	\N	\N	{"onboardingAnswers": {"goal": "Strength", "sport": "None", "style": "Strength training", "injuries": "None", "timeline": "6 months", "equipment": ["Barbell", "Dumbbells", "Pull-up bar"], "frequency": 4, "experience": "Intermediate"}, "firstProgramOutput": {"days": [{"name": "Day 1 — Lower A — Squat Focus", "focus": "Quad-dominant squat patterns, hinge accessory, posterior chain", "dayNotes": "Week 1: establish your baseline loads. Record weights on every set — progressive overload is tracked from here.", "dayNumber": 1, "exercises": [{"name": "Box Jump", "reps": "3-5", "rest": "3 min", "sets": 3, "notes": "Jump onto box, land in squat position. Focus on landing mechanics — soft and quiet.", "classification": "Plyometric/Explosive"}, {"name": "Box Squat", "reps": "3-5", "rest": "3-4 min", "sets": 4, "notes": "Pause and reset on the box — no bounce. Breaks the stretch-shortening cycle.", "classification": "Primary"}, {"name": "Sumo Deadlift", "reps": "4-6", "rest": "2-3 min", "sets": 3, "notes": "Wide stance, toes out, shorter torso lever. More hip dominant, less back.", "classification": "Secondary Compound"}, {"name": "Romanian Deadlift", "reps": "4-6", "rest": "2-3 min", "sets": 3, "notes": "Push hips back, bar close to legs. Feel the hamstring stretch at the bottom, not the spine.", "classification": "Secondary Compound"}, {"name": "Plank with Shoulder Tap", "reps": "8-12", "rest": "60-90 sec", "sets": 2, "notes": "Touch opposite shoulder without rotating. Anti-rotation challenge during the plank pattern.", "classification": "Accessory"}, {"name": "Plank with Row", "reps": "8-12", "rest": "60-90 sec", "sets": 2, "notes": "Row a dumbbell in plank. Anti-rotation at its most demanding. Core and back combined.", "classification": "Accessory"}]}, {"name": "Day 2 — Upper A — Push", "focus": "Horizontal & vertical press, shoulder stability, tricep accessory", "dayNumber": 2, "exercises": [{"name": "Close-Grip Bench Press", "reps": "3-5", "rest": "3-4 min", "sets": 4, "notes": "Hands shoulder-width. Tricep-biased press. Elbows tuck to the sides.", "classification": "Primary"}, {"name": "Barbell Row", "reps": "4-6", "rest": "2-3 min", "sets": 3, "notes": "Hinge over with flat back, row to lower chest. Classic horizontal pulling strength builder.", "classification": "Secondary Compound"}, {"name": "Barbell Row (Underhand)", "reps": "4-6", "rest": "2-3 min", "sets": 3, "notes": "Supinated grip recruits more biceps and lower lats. More elbow flexion in the movement.", "classification": "Secondary Compound"}, {"name": "Pallof Press Iso Hold", "reps": "8-12", "rest": "60-90 sec", "sets": 2, "notes": "Extended Pallof hold for time. Longer lever creates more anti-rotation demand.", "classification": "Accessory"}, {"name": "Half-Kneeling Pallof Press", "reps": "8-12", "rest": "60-90 sec", "sets": 2, "notes": "One knee down. Eliminates lower body contribution and increases anti-rotation demand.", "classification": "Accessory"}]}, {"name": "Day 3 — Lower B — Hinge Focus", "focus": "Hinge-dominant, posterior chain, unilateral legs", "dayNumber": 3, "exercises": [{"name": "DB Power Clean", "reps": "3-5", "rest": "3 min", "sets": 3, "notes": "Dumbbell version. Lower skill demand — good intro to triple extension and explosive pulling.", "classification": "Plyometric/Explosive"}, {"name": "Sumo Deadlift", "reps": "3-5", "rest": "3-4 min", "sets": 4, "notes": "Wide stance, toes out, shorter torso lever. More hip dominant, less back.", "classification": "Primary"}, {"name": "Box Squat", "reps": "4-6", "rest": "2-3 min", "sets": 3, "notes": "Pause and reset on the box — no bounce. Breaks the stretch-shortening cycle.", "classification": "Secondary Compound"}, {"name": "Low Bar Squat", "reps": "4-6", "rest": "2-3 min", "sets": 3, "notes": "Bar on rear delts, more forward lean. Greater posterior chain engagement than high bar.", "classification": "Secondary Compound"}, {"name": "Side Plank with Rotation", "reps": "8-12", "rest": "60-90 sec", "sets": 2, "notes": "Rotate top arm under the body. Combines lateral stability with thoracic rotation.", "classification": "Accessory"}, {"name": "Side Plank with Hip Lift", "reps": "8-12", "rest": "60-90 sec", "sets": 2, "notes": "Hip dips down then back up. Dynamic lateral core loading.", "classification": "Accessory"}]}, {"name": "Day 4 — Upper B — Pull", "focus": "Vertical & horizontal pull, back thickness and arm accessory", "dayNumber": 4, "exercises": [{"name": "Chin-Up", "reps": "3-5", "rest": "3-4 min", "sets": 4, "notes": "Supinated grip — more bicep involvement. Often easier to perform than pull-ups.", "classification": "Primary"}, {"name": "Barbell Row", "reps": "4-6", "rest": "2-3 min", "sets": 3, "notes": "Hinge over with flat back, row to lower chest. Classic horizontal pulling strength builder.", "classification": "Secondary Compound"}, {"name": "Barbell Row (Underhand)", "reps": "4-6", "rest": "2-3 min", "sets": 3, "notes": "Supinated grip recruits more biceps and lower lats. More elbow flexion in the movement.", "classification": "Secondary Compound"}, {"name": "Bear Plank", "reps": "8-12", "rest": "60-90 sec", "sets": 2, "notes": "Quadruped with knees hovering 1 inch off ground. Core bracing and shoulder stability drill.", "classification": "Accessory"}, {"name": "Bird Dog", "reps": "8-12", "rest": "60-90 sec", "sets": 2, "notes": "Opposite arm and leg extend from quadruped. Spinal stability and anti-rotation. McGill foundational exercise.", "classification": "Accessory"}]}], "coachNote": "Focus on movement quality in week 1 — track every weight used. From week 2 we load progressively. Log any soreness or discomfort so adjustments can be made.", "rationale": "This program applies progressive overload across 4 weekly sessions. Exercises follow NSCA hierarchy (explosive → primary compound → secondary → accessory) and are filtered to your Barbell/Dumbbells/Pull-up bar setup. Volume and intensity are calibrated for your experience tier.", "coachIntro": "Based on your intermediate experience and strength focus, I've built a 4-day program that pulls from a library of 620 structured exercises — every selection is matched to your equipment, experience level, and any limitations you noted.", "programName": "Intermediate Strength Program — 4×/week", "weeklyStructure": "4-Day Upper/Lower Split", "progressionPrinciple": "Add 2.5–5% load or 1-2 reps when all sets are completed cleanly. Every fourth week: deload (reduce sets by 1, weights by 40%). Progress compounds first."}}	control
